import React from 'react';
import { Link } from 'react-router-dom';
import { Product } from '../types';
import { FontAwesomeIcon } from '@fortawesome/react-fontawesome';
import { faHeart as faSolidHeart, faHeart as faRegularHeart, faStar as faSolidStar, faStarHalfAlt, faStar as faRegularStar, faPlayCircle } from '@fortawesome/free-solid-svg-icons';
import { IconDefinition } from '@fortawesome/free-brands-svg-icons';

interface ProductCardProps {
  product: Product;
  isFavorite: boolean;
  onFavoriteToggle: (id: number) => void;
  categoryIcon: { icon: IconDefinition; color: string };
  cardWidthPx?: number;
  linkTo?: string;
}

const ProductCard: React.FC<ProductCardProps> = ({
  product,
  isFavorite,
  onFavoriteToggle,
  categoryIcon,
  cardWidthPx,
  linkTo
}) => {
  // ņ£ĀĒŖ£ļĖī ņāüĒÆłņØ┤ļ®┤ ĒöīļĀłņØ┤ļ▓äĒŖ╝, ņĢäļŗłļ®┤ ņåīņģ£ ņĢäņØ┤ņĮś
  const isYoutube = product.category === 'ņ£ĀĒŖ£ļĖī';
  return (
    <Link
      to={linkTo || `/products/${product.id}`}
      className="relative bg-white rounded-2xl shadow-md overflow-hidden hover:shadow-lg transition duration-300 flex-1 cursor-pointer group"
      style={cardWidthPx ? { minWidth: `${cardWidthPx}px`, maxWidth: `${cardWidthPx}px` } : {}}
    >
      {/* ņ”ÉĻ▓©ņ░ŠĻĖ░ ļ▓äĒŖ╝ */}
      <button
        className="absolute top-4 right-4 z-10"
        onClick={e => { e.preventDefault(); onFavoriteToggle(product.id); }}
      >
        <FontAwesomeIcon
          icon={isFavorite ? faSolidHeart : faRegularHeart}
          className={`text-2xl ${isFavorite ? 'text-red-500' : 'text-gray-300'}`}
        />
      </button>
      {/* ņ╣┤ļō£ ņāüļŗ© ļ░░Ļ▓Į + ņżæņĢÖ ņĢäņØ┤ņĮś */}
      <div
        className="relative flex items-center justify-center h-48 bg-cover bg-center"
        style={{
          backgroundImage: product.background ? `url(${product.background})` : product.image ? `url(${product.image})` : undefined,
          backgroundColor: !product.background && !product.image ? '#F3F4F6' : undefined
        }}
      >
        <div className="absolute inset-0 bg-black/10" />
        <div className="relative z-10 flex items-center justify-center">
          {isYoutube ? (
            <FontAwesomeIcon icon={faPlayCircle} className="text-red-500 text-6xl drop-shadow-lg" />
          ) : (
            <FontAwesomeIcon icon={categoryIcon.icon} className={`text-5xl ${categoryIcon.color} drop-shadow-lg`} />
          )}
        </div>
      </div>
      {/* ņ╣┤ļō£ ļé┤ņÜ® */}
      <div className="p-4">
        <h3 className="font-semibold text-gray-900 mb-1 text-base">{product.name}</h3>
        <p className="text-gray-500 text-xs mb-2 truncate">{product.description}</p>
        {/* ĒĢĀņØĖ/Ļ░ĆĻ▓® */}
        <div className="flex items-end gap-2 mb-1">
          {product.discountRate && (
            <span className="text-blue-600 font-bold text-base">{product.discountRate}%</span>
          )}
          {product.originalPrice && (
            <span className="text-gray-400 line-through text-sm">{product.originalPrice.toLocaleString()}ņøÉ</span>
          )}
          <span className="text-gray-900 font-bold text-base">{typeof product.price === 'number' ? product.price.toLocaleString() : product.price}ņøÉ</span>
        </div>
        {/* ļ│äņĀÉ/ļ”¼ļĘ░ */}
        <div className="flex items-center gap-1 mt-1">
          {/* ļ│äņĀÉ Ēæ£ņŗ£ */}
          {(() => {
            const stars = [];
            const rating = product.rating ?? 0;
            for (let i = 1; i <= 5; i++) {
              if (rating >= i) {
                stars.push(<FontAwesomeIcon key={i} icon={faSolidStar} className="text-yellow-400 text-sm" />);
              } else if (rating >= i - 0.5) {
                stars.push(<FontAwesomeIcon key={i} icon={faStarHalfAlt} className="text-yellow-400 text-sm" />);
              } else {
                stars.push(<FontAwesomeIcon key={i} icon={faRegularStar} className="text-gray-300 text-sm" />);
              }
            }
            return stars;
          })()}
          <span className="text-gray-700 font-medium ml-1 text-sm">{product.rating?.toFixed(1)}</span>
          <span className="text-gray-400 text-xs">({product.reviewCount?.toLocaleString()})</span>
        </div>
      </div>
    </Link>
  );
};

export default ProductCard;
